+/// Cache retention policy (in seconds)
+pub const CACHE_RETENTION_DAYS = 30;
+pub const CACHE_RETENTION_SECONDS = CACHE_RETENTION_DAYS * 24 * 60 * 60;
+
+/// Clean up old system prompt caches (older than CACHE_RETENTION_DAYS)
+/// Returns number of files deleted
+pub fn cleanupOldSystemPromptCaches(allocator: std.mem.Allocator) !usize {
+    const home = std.posix.getenv("HOME") orelse return error.NoHomeDir;
+    const cache_dir = try std.fmt.allocPrint(
+        allocator,
+        "{s}/.cache/zell/system-prompts",
+        .{home},
+    );
+    defer allocator.free(cache_dir);
+
+    // Open cache directory
+    var dir = std.fs.cwd().openDir(cache_dir, .{ .iterate = true }) catch |err| {
+        // Directory doesn't exist - nothing to clean
+        if (err == error.FileNotFound) return 0;
+        return err;
+    };
+    defer dir.close();
+
+    const now = std.time.timestamp();
+    var deleted_count: usize = 0;
+
+    // Iterate through cache files
+    var iter = dir.iterate();
+    while (try iter.next()) |entry| {
+        // Only process .kv files
+        if (entry.kind != .file) continue;
+        if (!std.mem.endsWith(u8, entry.name, ".kv")) continue;
+
+        // Get file metadata
+        const stat = dir.statFile(entry.name) catch continue;
+
+        // Check age (using mtime - last modified time)
+        const age_seconds = now - @as(i64, @intCast(@divFloor(stat.mtime, 1_000_000_000)));
+
+        if (age_seconds > CACHE_RETENTION_SECONDS) {
+            // Delete old cache file
+            dir.deleteFile(entry.name) catch |err| {
+                // Log but don't fail on individual file deletion errors
+                std.debug.print("Warning: Failed to delete old cache {s}: {}\n", .{ entry.name, err });
+                continue;
+            };
+            deleted_count += 1;
+        }
+    }
+
+    return deleted_count;
+}
+
+/// Clean up old conversation logs (older than CACHE_RETENTION_DAYS)
+/// Returns number of files deleted
+pub fn cleanupOldConversationLogs(allocator: std.mem.Allocator) !usize {
+    const home = std.posix.getenv("HOME") orelse return error.NoHomeDir;
+    const conv_base_dir = try std.fmt.allocPrint(
+        allocator,
+        "{s}/.cache/zell/conversations",
+        .{home},
+    );
+    defer allocator.free(conv_base_dir);
+
+    // Open conversations directory
+    var base_dir = std.fs.cwd().openDir(conv_base_dir, .{ .iterate = true }) catch |err| {
+        // Directory doesn't exist - nothing to clean
+        if (err == error.FileNotFound) return 0;
+        return err;
+    };
+    defer base_dir.close();
+
+    const now = std.time.timestamp();
+    var deleted_count: usize = 0;
+
+    // Iterate through model directories
+    var base_iter = base_dir.iterate();
+    while (try base_iter.next()) |model_entry| {
+        if (model_entry.kind != .directory) continue;
+
+        // Open model-specific conversation directory
+        var model_dir = base_dir.openDir(model_entry.name, .{ .iterate = true }) catch continue;
+        defer model_dir.close();
+
+        // Iterate through conversation log files
+        var log_iter = model_dir.iterate();
+        while (try log_iter.next()) |log_entry| {
+            if (log_entry.kind != .file) continue;
+            if (!std.mem.endsWith(u8, log_entry.name, ".jsonl")) continue;
+
+            // Get file metadata
+            const stat = model_dir.statFile(log_entry.name) catch continue;
+
+            // Check age
+            const age_seconds = now - @as(i64, @intCast(@divFloor(stat.mtime, 1_000_000_000)));
+
+            if (age_seconds > CACHE_RETENTION_SECONDS) {
+                // Delete old log file
+                model_dir.deleteFile(log_entry.name) catch |err| {
+                    std.debug.print("Warning: Failed to delete old conversation log {s}: {}\n", .{ log_entry.name, err });
+                    continue;
+                };
+                deleted_count += 1;
+            }
+        }
+    }
+
+    return deleted_count;
+}
